import Script from "next/script";
import { env } from "@/env";

export const UmamiAnalytics = () => {
  // Check if the Umami feature is explicitly enabled
  if (!env.NEXT_PUBLIC_FEATURE_UMAMI_ENABLED) {
    return null; // Return null if the feature is disabled
  }

  // Also check if the website ID is actually present
  if (!env?.NEXT_PUBLIC_UMAMI_WEBSITE_ID) {
    console.warn("Umami feature is enabled but Website ID is missing.");
    return null;
  }

  return (
    <Script
      src="https://analytics.lacy.sh/script.js"
      data-website-id={env?.NEXT_PUBLIC_UMAMI_WEBSITE_ID}
      defer
    />
  );
};

import Script from "next/script";
import { env } from "@/env";

/*
 * DataFast Analytics loader
 * Renders the tracking script when the feature flag is enabled and required envs exist.
 * @see https://datafa.st/docs/nextjs-app-router
 */
export const DataFastAnalytics = () => {
  if (!env.NEXT_PUBLIC_FEATURE_DATAFAST_ENABLED) {
    return null;
  }

  if (!env.NEXT_PUBLIC_DATAFAST_WEBSITE_ID) {
    // Feature is enabled but WEBSITE_ID is missing; skip rendering silently per analytics convention
    return null;
  }

  const dataDomain = env.NEXT_PUBLIC_DATAFAST_DOMAIN;

  return (
    <Script
      src="https://datafa.st/js/script.js"
      data-website-id={env.NEXT_PUBLIC_DATAFAST_WEBSITE_ID}
      {...(dataDomain ? { "data-domain": dataDomain } : {})}
      strategy="afterInteractive"
    />
  );
};

import { GoogleAnalytics as NextGoogleAnalytics } from "@next/third-parties/google";
import { env } from "@/env";

export const GoogleAnalytics = () => {
  if (!env.NEXT_PUBLIC_FEATURE_GOOGLE_ANALYTICS_ENABLED) {
    return null;
  }

  if (!env.NEXT_PUBLIC_GOOGLE_ANALYTICS_ID) {
    return null;
  }

  return <NextGoogleAnalytics gaId={env.NEXT_PUBLIC_GOOGLE_ANALYTICS_ID} />;
};

import { GoogleTagManager as NextGoogleTagManager } from "@next/third-parties/google";
import { env } from "@/env";

export const GoogleTagManager = () => {
  if (!env.NEXT_PUBLIC_FEATURE_GOOGLE_TAG_MANAGER_ENABLED || !env.NEXT_PUBLIC_GOOGLE_GTM_ID) {
    return null;
  }

  return <NextGoogleTagManager gtmId={env.NEXT_PUBLIC_GOOGLE_GTM_ID} />;
};

"use client";
import { StatsigProvider, useClientAsyncInit } from "@statsig/react-bindings";
import { StatsigSessionReplayPlugin } from "@statsig/session-replay";
import { StatsigAutoCapturePlugin } from "@statsig/web-analytics";
import type React from "react";
import { env } from "@/env";
import { PageViewTracker } from "./statsig-pageview";

interface ProviderProps {
  children: React.ReactNode;
}

// Inner component that contains hooks - only rendered when Statsig is properly configured
function StatsigProviderInner({ children }: ProviderProps) {
  const clientKey = env.NEXT_PUBLIC_STATSIG_CLIENT_KEY;
  const user = { userID: undefined as string | undefined };

  const { client } = useClientAsyncInit(clientKey ?? "", user, {
    plugins: [new StatsigAutoCapturePlugin(), new StatsigSessionReplayPlugin()],
  });

  if (!client) {
    return children;
  }

  return (
    <StatsigProvider client={client}>
      <PageViewTracker />
      {children}
    </StatsigProvider>
  );
}

// Lightweight wrapper to conditionally render Statsig only when enabled and key present
export function ShipkitStatsigProvider({ children }: ProviderProps) {
  // Check conditions before rendering any hooks
  if (!env.NEXT_PUBLIC_FEATURE_STATSIG_ENABLED) {
    return <>{children}</>;
  }

  if (!env.NEXT_PUBLIC_STATSIG_CLIENT_KEY) {
    // Feature flag enabled by build-time detection, but key missing at runtime
    return <>{children}</>;
  }

  return <StatsigProviderInner>{children}</StatsigProviderInner>;
}

"use client";
import { useStatsigClient } from "@statsig/react-bindings";
import { useEffect } from "react";

export function PageViewTracker() {
  const { client } = useStatsigClient();

  useEffect(() => {
    if (!client) return;
    // Optional: capture an initial page view event
    client.logEvent("$pageview");
  }, [client]);

  return null;
}

import { Analytics as VercelAnalytics } from "@vercel/analytics/react";
import { SpeedInsights } from "@vercel/speed-insights/next";
import type { ReactNode } from "react";
import { WebVitals } from "@/components/primitives/web-vitals";
import { DataFastAnalytics } from "@/lib/datafast/datafast-analytics";
import { GoogleAnalytics } from "@/lib/google-analytics/google-analytics";
import { GoogleTagManager } from "@/lib/google-tag-manager/google-tag-manager";
import { ShipkitStatsigProvider } from "@/lib/statsig/statsig-provider";
import { UmamiAnalytics } from "@/lib/umami/umami-analytics";

export const AnalyticsProvider = ({ children }: { children: ReactNode }) => {
  return (
    <>
      <ShipkitStatsigProvider>
        {/* Web Vitals - Above children to track page metrics */}
        <WebVitals />

        {children}

        {/* Metrics - Below children to avoid blocking */}
        <SpeedInsights />

        {/* Analytics */}
        <GoogleAnalytics />
        <GoogleTagManager />
        <UmamiAnalytics />
        <DataFastAnalytics />
        <VercelAnalytics />
      </ShipkitStatsigProvider>
    </>
  );
};

import { ConsentManagerDialog, ConsentManagerProvider, CookieBanner } from "@c15t/nextjs";
import type { ReactNode } from "react";
import { env } from "@/env";

export default function ConsentProvider({ children }: { children: ReactNode }) {
  if (!env?.NEXT_PUBLIC_FEATURE_C15T_ENABLED) {
    return children;
  }

  return (
    <ConsentManagerProvider
      options={
        env?.NEXT_PUBLIC_C15T_URL
          ? { mode: "c15t", backendURL: env?.NEXT_PUBLIC_C15T_URL }
          : { mode: "offline" }
      }
    >
      {children}
      <CookieBanner />
      <ConsentManagerDialog />
    </ConsentManagerProvider>
  );
}
